package org.apache.commons.dbcp2.managed;

public class PoolableManagedConnection extends PoolableConnection { private final TransactionRegistry transactionRegistry ; public PoolableManagedConnection ( final TransactionRegistry transactionRegistry , final Connection conn , final ObjectPool < PoolableConnection > pool ) { this ( transactionRegistry , conn , pool , null , true ) ; } public PoolableManagedConnection ( final TransactionRegistry transactionRegistry , final Connection conn , final ObjectPool < PoolableConnection > pool , final Collection < String > disconnectSqlCodes , final boolean fastFailValidation ) { super ( conn , pool , null , disconnectSqlCodes , fastFailValidation ) ; this . transactionRegistry = transactionRegistry ; } @ Override public void reallyClose ( ) throws SQLException { try { super . reallyClose ( ) ; } finally { transactionRegistry . unregisterConnection ( this ) ; } } }